 66→function renderTextWithBoldPrefix(text: string) {
 67→  const match = text.match(/^([^:\n]{1,120}:)(\s*)(.*)$/);
 68→
 69→  if (!match) {
 70→    return text;
 71→  }
 72→
 73→  return (
 74→    <>
 75→      <strong>{match[1]}</strong>
 76→      {match[2]}
 77→      {match[3]}
 78→    </>
 79→  );
 80→}
 81→
 82→function renderTextWithMarkdownStrong(text: string) {
 83→  const parts = text.split(/(\*\*[^*\n][^*\n]*\*\*|__[^_\n][^_\n]*__)/g);
 84→
 85→  if (parts.length === 1) {
 86→    return text;
 87→  }
 88→
 89→  return parts.map((part) => {
 90→    const strongMatch =
 91→      part.match(/^\*\*([^*\n][^*\n]*)\*\*$/) ??
 92→      part.match(/^__([^_\n][^_\n]*)__$/);
 93→
 94→    if (!strongMatch) {
 95→      return part;
 96→    }
 97→
 98→    return <strong key={`strong-${strongMatch[1]}`}>{strongMatch[1]}</strong>;
 99→  });
100→}
101→
102→function resolveTextTransform(effects: RuleEffect[]) {
103→  const custom = collectCustomStyles(effects);
104→  if (custom.textTransform) return custom.textTransform;
105→  // Default: render markdown strong (existing behavior)
106→  return "render_markdown_strong" as const;
107→}
108→
109→function renderReaderInlineText(
110→  text: string,
111→  effects: RuleEffect[],
112→  textStyle?: React.CSSProperties,
113→) {
114→  const transform = resolveTextTransform(effects);
115→
116→  const rendered =
117→    transform === "bold_prefix_before_colon"
118→      ? renderTextWithBoldPrefix(text)
119→      : renderTextWithMarkdownStrong(text);
120→
121→  if (textStyle) {
122→    return <span style={textStyle}>{rendered}</span>;
123→  }
124→  return rendered;
125→}
