  8→  defaultRegistry,
  9→  normalizeLegacyEffect,
 10→  ruleEffectSchema,
 11→  ruleSelectorSchema,
 12→} from "@chat-exporter/shared";
 13→
 14→import { blockToPlainText } from "./reader-block-render";
 15→import { matchesReaderRule, type ReaderMatchContext } from "./rule-matching";
 16→
 17→// Re-exports for backward compatibility
 18→export {
 19→  blockToPlainText,
