        page.wait_for_timeout(300)

    del_btn = page.locator('button[aria-label="Block löschen"]')
    if del_btn.count() > 0 and del_btn.is_visible():
        del_btn.click()
        page.wait_for_timeout(800)
        page.screenshot(path='/tmp/qa-vis-2-after-delete.png', full_page=False)
        print("\n3. After DELETE - screenshot taken")

        after_del = page.evaluate('''() => {
            const editables = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
            return Array.from(editables).filter(el => el.offsetParent !== null).map(el => el.textContent.trim().substring(0, 50));
        }''')
        print(f"   Visible block texts: {after_del}")

    # === INSERT new block ===
    visible_editables = [e for e in page.locator('[contenteditable="true"], [contenteditable="plaintext-only"]').all() if e.is_visible()]
    if visible_editables:
        visible_editables[0].hover()
        page.wait_for_timeout(300)

    ins_btn = page.locator('button[aria-label="Block einfügen"]')
    if ins_btn.count() > 0 and ins_btn.is_visible():
        ins_btn.click()
        page.wait_for_timeout(400)
        para = page.locator('text=Heading (H2)').first
        if para.count() > 0 and para.is_visible():
            para.click()
            page.wait_for_timeout(800)
            page.screenshot(path='/tmp/qa-vis-3-after-insert-h2.png', full_page=False)
            print("\n4. After INSERT H2 - screenshot taken")

            after_ins = page.evaluate('''() => {
                const editables = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
                return Array.from(editables).filter(el => el.offsetParent !== null).map(el => ({
                    text: el.textContent.trim().substring(0, 50),
                    tag: el.tagName
                }));
            }''')
            print(f"   Visible blocks: {after_ins}")

    # === Final: Check React key stability via DOM ===
    print("\n5. React key check (via DOM):")
    keys = page.evaluate('''() => {
        // React fiber keys are not directly accessible from DOM
        // But we can check data attributes or key-like patterns
        const blocks = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
        return Array.from(blocks).filter(el => el.offsetParent !== null).map(el => {
            const parent = el.parentElement;
            const grandparent = parent?.parentElement;
            return {
                text: el.textContent.trim().substring(0, 30),
                parentTag: parent?.tagName,
                gpTag: grandparent?.tagName,
                gpClass: grandparent?.className?.substring(0, 60)
            };
        });
    }''')
    for k in keys:
        print(f"   {k}")

    page.screenshot(path='/tmp/qa-vis-final.png', full_page=True)
    print("\n✅ Visual QA complete - check /tmp/qa-vis-*.png")

    browser.close()

