import { z } from "zod";

import { blockSchema } from "./conversation.js";

// --- Entity Schemas (API-level representations) ---

export const conversationSnapshotSchema = z.object({
  id: z.string(),
  importId: z.string(),
  label: z.string(),
  isActive: z.boolean(),
  createdAt: z.string(),
  updatedAt: z.string(),
});

export const messageEditSchema = z.object({
  id: z.string(),
  importId: z.string(),
  snapshotId: z.string(),
  messageId: z.string(),
  editedBlocks: z.array(blockSchema),
  annotation: z.string().optional(),
  createdAt: z.string(),
  updatedAt: z.string(),
});

// --- Request Schemas ---

export const saveMessageEditRequestSchema = z.object({
  importId: z.string(),
  snapshotId: z.string(),
  messageId: z.string(),
  editedBlocks: z.array(blockSchema),
  annotation: z.string().optional(),
});

export const deleteMessageEditRequestSchema = z.object({
  importId: z.string(),
  snapshotId: z.string(),
  messageId: z.string(),
});

export const createSnapshotRequestSchema = z.object({
  importId: z.string(),
  label: z.string(),
});

export const activateSnapshotRequestSchema = z.object({
  importId: z.string(),
  snapshotId: z.string(),
});

export const renameSnapshotRequestSchema = z.object({
  importId: z.string(),
  snapshotId: z.string(),
  label: z.string(),
});

// --- Response Schemas ---

export const resolvedMessageSchema = z.object({
  messageId: z.string(),
  blocks: z.array(blockSchema),
  isEdited: z.boolean(),
});

// --- Inferred Types ---

export type ConversationSnapshot = z.infer<typeof conversationSnapshotSchema>;
export type MessageEdit = z.infer<typeof messageEditSchema>;
export type SaveMessageEditRequest = z.infer<
  typeof saveMessageEditRequestSchema
>;
export type DeleteMessageEditRequest = z.infer<
  typeof deleteMessageEditRequestSchema
>;
export type CreateSnapshotRequest = z.infer<typeof createSnapshotRequestSchema>;
export type ActivateSnapshotRequest = z.infer<
  typeof activateSnapshotRequestSchema
>;
export type RenameSnapshotRequest = z.infer<typeof renameSnapshotRequestSchema>;
export type ResolvedMessage = z.infer<typeof resolvedMessageSchema>;

import { nanoid } from "nanoid";
import { z } from "zod";

export const generateBlockId = () => nanoid(8);

const blockIdField = { id: z.string().default(() => nanoid(8)) };

export const sourcePlatformSchema = z.enum([
  "chatgpt",
  "claude",
  "gemini",
  "grok",
  "deepseek",
  "notebooklm",
  "unknown",
]);

export const roleSchema = z.enum([
  "system",
  "user",
  "assistant",
  "tool",
  "unknown",
]);

export const paragraphBlockSchema = z
  .object({
    type: z.literal("paragraph"),
    text: z.string(),
  })
  .extend(blockIdField);

export const headingBlockSchema = z
  .object({
    type: z.literal("heading"),
    level: z.number().int().min(1).max(6),
    text: z.string(),
  })
  .extend(blockIdField);

export const listBlockSchema = z
  .object({
    type: z.literal("list"),
    ordered: z.boolean(),
    items: z.array(z.string()),
  })
  .extend(blockIdField);

export const codeBlockSchema = z
  .object({
    type: z.literal("code"),
    language: z.string().default("text"),
    text: z.string(),
  })
  .extend(blockIdField);

export const quoteBlockSchema = z
  .object({
    type: z.literal("quote"),
    text: z.string(),
  })
  .extend(blockIdField);

export const tableBlockSchema = z
  .object({
    type: z.literal("table"),
    headers: z.array(z.string()),
    rows: z.array(z.array(z.string())),
  })
  .extend(blockIdField);

export const blockSchema = z.discriminatedUnion("type", [
  paragraphBlockSchema,
  headingBlockSchema,
  listBlockSchema,
  codeBlockSchema,
  quoteBlockSchema,
  tableBlockSchema,
]);

export const messageSchema = z.object({
  id: z.string(),
  role: roleSchema,
  blocks: z.array(blockSchema),
});

export const conversationSchema = z.object({
  id: z.string(),
  title: z.string(),
  source: z.object({
    url: z.string().url(),
    platform: sourcePlatformSchema,
  }),
  messages: z.array(messageSchema),
});

export type SourcePlatform = z.infer<typeof sourcePlatformSchema>;
export type Role = z.infer<typeof roleSchema>;
export type Block = z.infer<typeof blockSchema>;
export type Message = z.infer<typeof messageSchema>;
export type Conversation = z.infer<typeof conversationSchema>;

