from playwright.sync_api import sync_playwright
import json

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={"width": 1280, "height": 900})

    # Capture console logs
    logs = []
    page.on("console", lambda msg: logs.append(f"[{msg.type}] {msg.text}"))

    # Capture network requests to the edits.save endpoint
    requests_log = []
    def log_request(request):
        if "edits" in request.url or "save" in request.url:
            try:
                body = request.post_data
                if body:
                    requests_log.append(f"POST {request.url}: {body[:200]}")
            except:
                pass

    def log_response(response):
        if "edits" in response.url or "save" in response.url:
            try:
                requests_log.append(f"RESP {response.url} status={response.status}")
            except:
                pass

    page.on("request", log_request)
    page.on("response", log_response)

    # Use a fresh conversation
    page.goto('http://localhost:5174/history')
    page.wait_for_load_state('networkidle')
    page.wait_for_timeout(1000)

    # Click on a "Test conversation" that hasn't been modified
    rows = page.locator('td:has-text("Test conversation")').all()
    if len(rows) >= 8:
        rows[7].click()
    else:
        rows[-1].click()
    page.wait_for_load_state('networkidle')
    page.wait_for_timeout(1000)
    print(f"URL: {page.url}")

    # Enter edit mode
    page.locator('button[title="Bearbeiten"]').click()
    page.wait_for_timeout(500)

    # Get initial block count
    initial_texts = page.evaluate('''() => {
        const els = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
        return Array.from(els).filter(el => el.offsetParent !== null).map(el => el.textContent.trim().substring(0, 50));
    }''')
    print(f"\nInitial blocks: {initial_texts}")

    # Clear logs before operation
    logs.clear()
    requests_log.clear()

    # Insert a CODE block
    print("\n=== Inserting CODE block ===")
    page.locator('text=Hi there').first.hover()
    page.wait_for_timeout(300)
    page.locator('button[aria-label="Block einfügen"]').click()
    page.wait_for_timeout(400)
    page.locator('text=Code').first.click()

    # Wait for debounce + server round-trip
    page.wait_for_timeout(2000)

    after_code = page.evaluate('''() => {
        const els = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
        return Array.from(els).filter(el => el.offsetParent !== null).map(el => ({
            text: el.textContent.trim().substring(0, 50),
            tag: el.tagName
        }));
    }''')
    print(f"After CODE insert (2s): {after_code}")

    # Print network requests
    print(f"\nNetwork requests: {len(requests_log)}")
    for r in requests_log:
        print(f"  {r}")

    # Print relevant console logs
    error_logs = [l for l in logs if 'error' in l.lower() or 'warn' in l.lower() or 'block' in l.lower()]
    print(f"\nRelevant console logs: {len(error_logs)}")
    for l in error_logs[:20]:
        print(f"  {l}")

    page.screenshot(path='/tmp/qa-debug-code.png', full_page=False)

    # Now try inserting a LIST block
    logs.clear()
    requests_log.clear()
    print("\n=== Inserting LIST block ===")

    visible = page.locator('[contenteditable="true"], [contenteditable="plaintext-only"]').all()
    visible_els = [e for e in visible if e.is_visible()]
    if visible_els:
        visible_els[0].hover()
        page.wait_for_timeout(300)

    ins = page.locator('button[aria-label="Block einfügen"]')
    if ins.count() > 0 and ins.is_visible():
        ins.click()
        page.wait_for_timeout(400)
        list_opt = page.locator('text=List').first
        if list_opt.count() > 0 and list_opt.is_visible():
            list_opt.click()
            page.wait_for_timeout(2000)

    after_list = page.evaluate('''() => {
        const els = document.querySelectorAll('[contenteditable="true"], [contenteditable="plaintext-only"]');
        return Array.from(els).filter(el => el.offsetParent !== null).map(el => ({
            text: el.textContent.trim().substring(0, 50),
            tag: el.tagName
        }));
    }''')
    print(f"After LIST insert (2s): {after_list}")

    print(f"\nNetwork requests: {len(requests_log)}")
    for r in requests_log:
        print(f"  {r}")

    error_logs = [l for l in logs if 'error' in l.lower() or 'warn' in l.lower()]
    print(f"\nRelevant console logs: {len(error_logs)}")
    for l in error_logs[:20]:
        print(f"  {l}")

    page.screenshot(path='/tmp/qa-debug-list.png', full_page=False)

    browser.close()

